// n8n Code node (JavaScript)
const items = $input.all();

return items.map(item => {
  // 1) Tomamos la salida del extractor
  let raw = item.json.output ?? "";

  // 2) Aseguramos que sea string
  if (typeof raw !== "string") {
    try { raw = JSON.stringify(raw); } catch (e) { raw = String(raw ?? ""); }
  }

  // 3) Extraer el contenido entre ```json ... ``` o ``` ... ```
  let body = raw;
  const fencedJson = raw.match(/```(?:json)?\s*([\s\S]*?)```/i);
  if (fencedJson && fencedJson[1]) {
    body = fencedJson[1].trim();
  }

  // 4) Intentar parsear el JSON
  let data = {};
  try {
    data = JSON.parse(body);
  } catch (e) {
    // Fallback: buscar el primer {...} dentro del string por si vino con texto extra
    const objMatch = body.match(/\{[\s\S]*\}/);
    if (objMatch) {
      try { data = JSON.parse(objMatch[0]); } catch (e2) {}
    }
  }

  // 5) Devolver integrando los campos parseados (sin tocar otras propiedades del item)
  return {
    json: {
      ...item.json,
      contratante_nombre: data.contratante_nombre ?? null,
      contratante_id: data.contratante_id ?? null,
      contratista_nombre: data.contratista_nombre ?? null,
      contratista_id: data.contratista_id ?? null,
      servicio_descripcion: data.servicio_descripcion ?? null,
      plazo_inicio: data.plazo_inicio ?? null,
      plazo_fin: data.plazo_fin ?? null,
      duracion_meses: data.duracion_meses ?? null,
      duracion_dias: data.duracion_dias ?? null,
      precio_monto: data.precio_monto ?? null,
      precio_moneda: data.precio_moneda ?? null,
      ciudad: data.ciudad ?? null,
      pais: data.pais ?? null,
      texto_usuario: item.json.texto_usuario ?? null,
    }
  };
});

const d = items[0].json || {};

function toNumber(x) {
  if (x === null || x === undefined) return null;
  if (typeof x === 'number') return x;
  const n = String(x).replace(/[.,](?=\d{3}\b)/g, '').replace(',', '.');
  const val = Number(n);
  return Number.isFinite(val) ? val : null;
}

const datos = {
  contratante_nombre: d.contratante_nombre ?? null,
  contratante_id: d.contratante_id ?? null,
  contratista_nombre: d.contratista_nombre ?? null,
  contratista_id: d.contratista_id ?? null,
  servicio_descripcion: d.servicio_descripcion ?? null,
  plazo_inicio: d.plazo_inicio ?? null,
  plazo_fin: d.plazo_fin ?? null,
  duracion_meses: d.duracion_meses ?? null, // NUEVO
  duracion_dias: d.duracion_dias ?? null,   // opcional
  precio_monto: toNumber(d.precio_monto),
  precio_moneda: d.precio_moneda ?? null,
  ciudad: d.ciudad ?? null,
  pais: d.pais ?? null
};

// Reglas de mínimo
const baseOblig = [
  'contratante_nombre','contratante_id',
  'contratista_nombre','contratista_id',
  'servicio_descripcion','precio_monto','precio_moneda','pais'
];

const faltantes = [];
for (const k of baseOblig) {
  const v = datos[k];
  if (k === 'precio_monto') {
    if (!(typeof v === 'number' && Number.isFinite(v))) faltantes.push(k);
  } else if (v === null || (typeof v === 'string' && v.trim() === '')) {
    faltantes.push(k);
  }
}

// Fecha: aceptar "plazo_fin" O "duración"
const tieneFin = datos.plazo_fin && String(datos.plazo_fin).trim() !== '';
const tieneDuracion = (datos.duracion_meses && Number(datos.duracion_meses) > 0) || 
                      (datos.duracion_dias && Number(datos.duracion_dias) > 0);
if (!tieneFin && !tieneDuracion) {
  faltantes.push('plazo_fin (o duracion)');
}

return [{ json: { ok: faltantes.length === 0, faltantes, datos } }];

const d = items[0].json.datos || items[0].json;

function addMonths(date, months) {
  const dt = new Date(date.getTime());
  const day = dt.getDate();
  dt.setMonth(dt.getMonth() + months);
  if (dt.getDate() < day) dt.setDate(0);
  return dt;
}
function addDays(date, days) { const dt = new Date(date.getTime()); dt.setDate(dt.getDate()+days); return dt; }
function iso(x){ return x.toISOString().slice(0,10); }

let inicio = d.plazo_inicio ? new Date(d.plazo_inicio) : new Date(); // hoy
let fin = d.plazo_fin ? new Date(d.plazo_fin) : null;

const meses = Number(d.duracion_meses || 0);
const dias = Number(d.duracion_dias || 0);

if (!fin && (meses>0 || dias>0)) {
  let tmp = new Date(inicio.getTime());
  if (meses>0) tmp = addMonths(tmp, meses);
  if (dias>0)  tmp = addDays(tmp, dias);
  fin = tmp;
}

return [{
  json: {
    ...d,
    plazo_inicio: iso(inicio),
    plazo_fin: iso(fin ?? inicio),  // por seguridad
    // útil para el contrato:
    duracion_texto: meses ? `${meses} meses` : (dias ? `${dias} días` : '')
  }
}];

const normativas = $json.normativas;

const clausulaLegal = normativas.map((n) => {
  return `• *${n.law_name}* (${n.topic}): ${n.summary} [Fuente](${n.sources[0]})`;
}).join("\n\n");

const clausulaFirma = `✍️ *Firma Electrónica*\n\nDe acuerdo con la *Ley 527 de 1999* y el *Decreto 2364 de 2012* de Estados Unidos, este contrato puede ser firmado electrónicamente y tiene plena validez jurídica y probatoria. Las partes reconocen que el uso de medios electrónicos constituye manifestación de voluntad y acuerdo entre ellas.`;

return [
  {
    json: {
      ...$json,
      clausula_legal: `📘 *Normativa Aplicable*\n\n${clausulaLegal}`,
      clausula_firma: clausulaFirma,
    }
  }
];

// Renombrar el archivo .pdf antes de enviarlo por Telegram

return items.map(item => {
  const binKeys = Object.keys(item.binary);
  if (binKeys.length === 0) return item; // no hay binarios

  const binName = binKeys[0]; // suele ser "data"

  // Nuevo nombre dinámico opcional
  const nuevoNombre = `Contrato_${new Date().toISOString().slice(0,10)}.pdf`;

  item.binary[binName].fileName = nuevoNombre;

  return item;
});
